components.customConditional:
switch(data.applicationStatus) {
  case "New":
  case "Approved":
  case "Rejected":
    show = false;
    break;
  default: show = true;
};

const UserDetails = JSON.parse(localStorage.getItem("UserDetails"))
const groups = UserDetails["groups"]

if(groups.includes("/formsflow/formsflow-reviewer") && data.applicationStatus==="New") {
show = true;
}
else {
show = false;
};

components.custom:
const submissionId = form._submission._id;
// Set base URL 
Formio.setBaseUrl(form.formio.projectUrl + '/formio');

const formRelativePath = '/form/' + form.formio.formId;

const submissionObj = {
  _id: submissionId,
  data: data
};
// Create Formio instance using relative path
const formio = new Formio(formRelativePath);
formio.saveSubmission(submissionObj).then(result => {
  console.log('Submission saved:', result);
  form.emit('customEvent', {
    type: "actionComplete",
    component: component,
    actionType: data.actionType
  });
}).catch(error => {
  console.error('Error saving submission:', error);
});

